mapper.select:
SELECT c.id, c.class_name, c.class_code, c.grade_level, c.grade_id, c.department_id, d.dept_name as department_name, c.major_id, m.major_name as major_name, c.major_direction_id, md.direction_name as major_direction_name, CONCAT(c.enrollment_year, '级') as grade, c.teacher_id, t.real_name as teacher_name, c.assistant_teacher_id, at.real_name as assistant_teacher_name, (SELECT COUNT(*) FROM students s WHERE s.class_id = c.id AND s.deleted = 0) as student_count, 50 as max_students, c.classroom_location, c.enrollment_year, c.graduation_year, c.class_type, CASE c.class_type WHEN 1 THEN '普通班' WHEN 2 THEN '重点班' WHEN 3 THEN '实验班' ELSE '未知' END as class_type_name, c.status, CASE c.status WHEN 1 THEN '启用' WHEN 0 THEN '禁用' ELSE '未知' END as status_name, c.created_at, c.updated_at FROM classes c LEFT JOIN departments d ON c.department_id = d.id LEFT JOIN majors m ON c.major_id = m.id LEFT JOIN major_directions md ON c.major_direction_id = md.id LEFT JOIN users t ON c.teacher_id = t.id LEFT JOIN users at ON c.assistant_teacher_id = at.id WHERE c.deleted = 0
AND c.class_name LIKE CONCAT('%', #{req.className}, '%')
AND c.class_code LIKE CONCAT('%', #{req.classCode}, '%')
AND c.grade_level = #{req.gradeLevel}
AND c.grade_id = #{req.gradeId}
AND c.department_id = #{req.departmentId}
AND c.teacher_id = #{req.teacherId}
AND c.enrollment_year = #{req.enrollmentYear}
AND c.class_type = #{req.classType}
AND c.status = #{req.status}
AND c.id IN #{cid}
AND c.department_id IN #{did}
ORDER BY c.grade_level ASC, c.class_name ASC ORDER BY c.grade_level DESC, c.class_name ASC
ORDER BY c.class_name ASC ORDER BY c.class_name DESC
ORDER BY student_count ASC ORDER BY student_count DESC
ORDER BY c.created_at ASC ORDER BY c.created_at DESC

SELECT COUNT(*)
FROM classes
WHERE class_code = #{classCode}
AND deleted = 0

    AND id != #{excludeId}
